function show$&Identity;$(f) {
  var z = f.grid, h = z.get_element().parentForm, queryFilterString = '', c = String.fromCharCode(253);
  queryFilterString = h.getItemValue('ma_dvcs');
  queryFilterString += c + h.getItemValue('ma_kh');
  queryFilterString += c + z._filter$Fields[0];
  var d = h.getItemValue('ngay_lct').z;

  queryFilterString += c + d.getFullYear() + ('0' + (d.getMonth() + 1)).slice(-2) + ('0' + d.getDate()).slice(-2);

  show$FlowMulti$Form(f, queryFilterString, '&Identity;DataGridPanel', '&ParentController;', '&GridController;', '&OtherCopyField;');
}

function active$&Identity;$(f) {
  f.add_onResponseComplete(on$&Identity;Form$ResponseComplete);
  active$FlowMulti$Form(f);
}

function close$&Identity;$(f) {
  close$FlowMulti$Form(f);
  try {f.remove_onResponseComplete(on$&Identity;Form$ResponseComplete);} catch (ex) {}
}

function on$&Identity;Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = getGrid$FlowMulti$(f);
      var c = String.fromCharCode(255), k1 = g._getColumnOrder('stt_rec') - 1, k2 = g._getColumnOrder('stt_rec0') - 1;
      f._$k = '';
      for(var i = 0; i < g._$k.length; i++) {
        f._$k += (f._$k != '' ? ',' : '') + g._$k[i][k1] + c + g._$k[i][k2];
      }
      if (f._$k == '') f.grid._formScript = 'show$FlowMulti$RetrieveGrid(this)';
      else {
        f._checked = false;
        f.request('GetOtherField', 'GetOtherField', [['k', 'Infinite', f._$k]]);
      }
      break;
    case 'GetOtherField':
      var g = getGrid$FlowMulti$(f), a = [];
      for (var i = 0; i < result.length; i++) {
        a[i] = g._$k[i].concat(result[i].slice(2));
      }
      on$&Identity;$TransferData(f, g, a);
      break;
    default:
      break;
  }
}
function on$&Identity;$TransferData(f, g, a) {
  var z = f.grid, w = z.get_element().parentForm, f1 = 'so_luong0, stt_rec, stt_rec0', f2 = 'so_luong, stt_rec_bg, stt_rec0bg';
  var first = true, qf = f._$queryFilterString.split(String.fromCharCode(253));
  var ma_nt = w.getItemValue('ma_nt'), m = qf[1], l0 = z._getColumnOrder('ma_vt'), l1 = z._getColumnOrder('dvt'), l2 = getColumnOrderTagRow(g, 'nhieu_dvt'), l3 = getColumnOrderTagRow(g, 'so_luong0'), l4 = getColumnOrderTagRow(g, 'so_luong');
  var externalFields = 'ck_nt, ck', fields = 'ma_vt, ten_vt%l, dvt, he_so, ma_kho, ngay_giao, ma_thue, thue_suat&FlowMultiUserDefinedFieldsCopy;';
  var l7 = getColumnOrderTagRow(g, 'ma_nt');

  for (var r = 0; r < a.length; r++) {
    var v = (ma_nt == a[r][l7]), map = fields;
    if (v) map += ', gia_ban_nt, gia_nt2';
    if (a[r][l3] != 0) {
      var ins = true, row = z._rowCount;
      if (first && row > 0) if (z.blankMemvar(row)) {ins = false; first = false;}
      if (ins) z._appendRow(null, true);
      row = z._rowCount;
      z._getItem(row, 1)._customerIdentity = m;
      var o = z._getItem(row, l0);
      o.row = row;
      var u = (a[r][l3] == a[r][l4]);
      insert$RetrieveTagRow$Items(g, a, r, z, row, u ? map + ', ' + externalFields: map, f1, f2);
      if (v) {
        z.executeExpression(o, [z.$a.gia_ban, z.$a.gia2, z.$a.tien_nt2, z.$a.tien2_tg, z.$a.thue_nt, z.$a.thue_tg]);
        if (u) z.executeExpression(o, [z.$a.ck]);
      }
      $func.setObjectWhen(z._getItem(row, l1), a[r][l2]);
    }
  }
  z.executeAggregate([z.$a.t_so_luong]);
  if (v) {
    z.executeAggregate([z.$a.t_tien_nt2, z.$a.t_tien2, z.$a.t_ck_nt, z.$a.t_ck, z.$a.t_thue_nt, z.$a.t_thue]);
    w.executeExpression([z.$a.t_tt_nt, z.$a.t_tt]);
  }
  z._focusWhenTabChanged();
  f.cancelDialog();
}
